VALUES
  ('judicial-57112235-moex-00387', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於監獄發生火災可能的潛在因素分析，下列敘述何者錯誤？', '["火災可能釀成受刑人群體脫逃之危險", "受刑人縱火可能係發洩緊張情緒與焦慮，或投射與補償等心理機轉而生之報復行為", "受刑人縱火是抗議行為之表現，與自殺之動機無關", "受刑人縱火可能是在暴動中展示暴力之行為表現型態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00388', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄受刑人自殺事故較常見的因素中，下列何者錯誤？', '["受刑人自殺方式常以自縊、食毒、吞食異物、割腕刺腹居多", "受刑人自殺成因常以久病不癒、訴訟或刑期過長過重、環境不適應及內心痛苦折磨居多", "受刑人自殺時間常以中午、午休時間居多", "受刑人自殺處所以獨居房、違規房、病舍居多"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00389', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄受刑人脫逃事故之常見因素，下列敘述何者錯誤？', '["受刑人脫逃事故的成因常以不適應監獄生活、思念親人或戒護人員的疏於防範始然", "常因戒護設備不周延、有死角，使受刑人有機可乘", "脫逃受刑人常以長刑期的暴力犯、年齡在60歲至70歲間居多", "受刑人脫逃類型常以暴力脫逃、破獄脫逃、單純脫逃或特殊脫逃為主"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00390', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關我國監獄行刑法制之沿革及其立法理由，下列敘述何者錯誤？', '["我國監獄制度始於夏朝", "現代監獄行刑之目的，使受刑人改悔向上與培養其適應社會生活之能力", "於民國25年公布「監獄規則」", "國民政府於民國35年1月19日重新制定「監獄行刑法」，共98條"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00391', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法與其他法規的關係，下列敘述何者錯誤？', '["監獄行刑法為多數犯罪矯正法規之母法，另其他相關犯罪矯正法規之內容，亦大體參考監獄行刑法 之內容或依其子法而訂定", "監獄行刑法係具體實現刑法規定刑罰之刑事法規，與刑法具有密切之關係", "監獄行刑法為本諸刑事訴訟之程序，具體實現刑事刑罰之執行規定，兩者相輔相成", "監獄為執行刑罰之處所，係屬法務行政組織，而監獄工作人員限制受刑人自由之行為，亦為司法審 判行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00392', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人入監時經健康檢查而應拒絕收監之情形，下列敘述何者錯誤？', '["懷胎3月以上，或生產未滿3月", "現罹患疾病，因執行而不能保其生命", "罹患法定傳染病，因執行有引起群聚感染之虞", "衰老、身心障礙，不能於監獄自理生活"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00393', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第1條之規定，我國監獄行刑矯治處遇目的，下列敘述何者正確？', '["僅強調促使受刑人改悔向上", "強調與社會隔離，應報之目的", "僅強調培養其適應社會生活之能力", "促使受刑人改悔向上，培養其適應社會生活之能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00394', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法之規定，下列敘述何者正確？', '["主管機關以及監獄的監督機關均為法務部矯正署，矯正署應每季至少1次派員視察監獄", "處有期徒刑、拘役及罰金易服勞役者，應與處無期徒刑者分別監禁", "未滿18歲之少年受刑人，應收容於少年矯正學校，所稱少年受刑人係指入監時未滿18歲之受刑人", "監獄對收容之受刑人，應按其性別嚴為分界"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00395', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人入監後，監獄會進行相關調查作業，以建立其個別化處遇之參考資料，有關調查作業之規定， 下列敘述何者錯誤？', '["入監調查於受刑人新入監後2個月內完成直接調查、間接調查及心理測驗", "刑期未滿1年之受刑人，其入監調查得以簡式方式行之", "在監複查於受刑人入監後每2年複查1次，必要時得隨時為之", "出監調查於受刑人期滿前3個月，或提報假釋前為之，必要時，得於釋放前再予覆查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00396', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人入監之規定，下列敘述何者正確？', '["受刑人入監時，無指揮書者，得拒絕收監", "裁判書及其他應備文件有欠缺時，不得通知補正", "個別處遇計畫，於入監後，由監獄所設之接收組擬具，提監務委員會議審議後，由相關單位人員執 行之", "受刑人入監後應編列號數，並編製身分簿及名籍資料"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
